#include <stdio.h>
int min(int a, int b) { return a < b ? a : b; }
int matrixChainOrder(int arr[], int i, int j) {
    if (i == j) return 0;
    int minCost = 999999999;
    for (int k = i; k < j; k++) {
        int cost1 = matrixChainOrder(arr, i, k);
        int cost2 = matrixChainOrder(arr, k + 1, j);
        int costMultiply = arr[i - 1] * arr[k] * arr[j];
        int total = cost1 + cost2 + costMultiply;
        minCost = min(minCost, total);
    }
    return minCost;
}
int main() {
    int arr[] = {40, 20, 30, 10, 30};
    int n = sizeof(arr) / sizeof(arr[0]);
    printf("%d\n", matrixChainOrder(arr, 1, n - 1));
    return 0;
}

